/**
 * method
 * @name f_get_cntrCntForMasterKey
 * @description 마스터키 관련정보 조회
 */
scwin.f_get_cntrCntForMasterKey = async function () {
  let odrCntrCnt = ds_ExportOnRequest.getRowCount(); //현재 오더의 컨테이너 개수
  if (odrCntrCnt == 0) {
    return true;
  }
  const retrieve = ds_retrieve.getRowJSON(0);
  if ($c.gus.cfIsNull($p, retrieve.masterKey)) {
    return true;
  }
  let brnCd = "";
  if (retrieve.pickuprgnCd == "EWY") {
    brnCd = "4BB";
  } else if (retrieve.pickuprgnCd == "INC") {
    brnCd = "4AA";
  } else if (retrieve.pickuprgnCd == "BUG") {
    brnCd = "3BB";
  }
  if ($c.gus.cfIsNull($p, brnCd)) {
    return true;
  }
  let tmpCntrSiz = "";
  let tmpCntrTyp = "";
  let regCnt = "0"; //오더의 컨테이너 등록개수
  let useCnt = "0"; //반출개수
  let usableCnt = "0"; //주당 반출가능 개수
  for (let i = 0; i < odrCntrCnt; ++i) {
    const nrm = ds_ExportOnRequest.getCellData(i, "nrm");
    const cntrSiz = nrm.substring(0, 2);
    const cntrTyp = nrm.substring(2, 4);
    if (cntrSiz != tmpCntrSiz && cntrTyp != tmpCntrTyp) {
      ds_masterKeyInfo.removeAll();
      dma_retrieveExportCommCd.setJSON({
        sysCd: "CommonEBC",
        queryId: "retrieveMasterKeyInfo",
        param1: brnCd,
        // 점소
        param2: retrieve.masterKey,
        // 마스터키
        param3: cntrSiz,
        // cntr size
        param4: cntrTyp // cntr type
      });
      await $c.sbm.execute($p, sbm_retrieveMasterKeyInfo);
      let masterKeyInfo = ds_masterKeyInfo.getRowJSON(0);
      if (!$c.gus.cfIsNull($p, masterKeyInfo.col1)) {
        regCnt = masterKeyInfo.col1; //등록개수
        useCnt = masterKeyInfo.col2; //반출개수
        usableCnt = masterKeyInfo.col3; //주당 반출가능 개수
      } else {
        await $c.win.alert($p, "요청한 마스터키의 SIZE/TYPE이 올바르지 않습니다.\n\n 위에 마스터키를 클릭하셔서 확인바랍니다.");
        return false;
      }
      tmpCntrSiz = cntrSiz;
      tmpCntrTyp = cntrTyp;
      await $c.win.alert($p, "마스터키 : " + retrieve.masterKey + "  (" + cntrSiz + "/" + cntrTyp + ")" + "\n\n" + "이번주 등록된 컨테이너 개수 : " + regCnt + "개\n\n" + "이번주 반출 개수 : " + useCnt + "개\n\n" + "주당 반출가능 개수 : " + usableCnt + "개");
      if ($c.num.parseInt($p, usableCnt) < $c.num.parseInt($p, useCnt) + $c.num.parseInt($p, odrCntrCnt)) {
        if (await $c.win.confirm($p, "반출가능 소진개수를 초과했습니다. 오더승인을 진행하시겠습니까?")) {
          return true; //초과이지만 확인후 진행
        } else {
          return false;
        }
      } else {
        return true; //가능하므로 진행
      }
    }
  }
  return false;
};

/**
 * method
 * @name f_CreateOrder
 * @description
 */
scwin.f_CreateOrder = async function () {
  if (!ds_retrieve.getRowCount()) {
    return;
  }
  if (!(await $c.gus.cfValidate($p, [gr_exportOnRequest]))) {
    return;
  }
  let retrieve = ds_retrieve.getRowJSON(0);
  if (retrieve.odrNo != "") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_001);
    return;
  }
  if (ds_ExportOnRequest.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_002);
    return;
  }
  if (retrieve.admitClsCd != "O" && retrieve.admitClsCd != "R") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_003, ["승인 또는 접수"]);
    return;
  }
  if (acb_admitClsCd2.getValue() == 'Y') {
    ds_retrieve.setCellData(0, "prebilgYn", 1);
  } else {
    ds_retrieve.setCellData(0, "prebilgYn", 0);
  }
  if (retrieve.lineCd == "WJS" && $c.gus.cfIsNull($p, tbx_odrNo.getValue())) {
    if (retrieve.jeVanTerm != acb_liVanTermCd.getValue()) {
      await $c.win.alert($p, "VANTERM이 일치하지 않습니다.");
      return;
    } else {
      ds_retrieve.setCellData(0, "liVanTerm", acb_liVanTermCd.getValue());
    }
  }
  if ($c.gus.cfIsNull($p, retrieve.odrNo)) {
    if (retrieve.lineCd == "SKR" && $c.gus.cfIsNull($p, acb_admitClsCd2.getValue())) {
      await $c.win.alert($p, "SKR라인 수출상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
      return;
    }
  }
  if (!(await scwin.f_get_cntrCntForMasterKey())) {
    return;
  }
  $c.sbm.execute($p, sbm_createExportGeneralOrder);
};

