/**
 * method
 * @name f_Cancel
 * @description 승인 취소
 */
scwin.f_Cancel = async function (gubun) {
  let retrieve = ds_retrieve.getRowJSON(0);
  if (gubun == "1") {
    if (await $c.win.confirm($p, scwin.MSG_OP_CFM_001)) {
      if (!ds_retrieve.getModifiedIndex().length) {
        //asis는 모든 변경사항이 없으면 서비스를 호출하지 않는다.
        scwin.sbm_cancel_submitdone({
          responseJSON: {}
        });
        return;
      }
      if (ed_vsslNm.getValue() != "") {
        ed_vsslCd.setValue(retrieve.vsslCd);
        ed_vsslNm.setValue(retrieve.vsslNm);
        ds_retrieve.setCellData(0, "vsslNm", retrieve.vsslCd);
      }
      $c.sbm.execute($p, sbm_cancel);
    }
  } else if (gubun == "2") {
    ds_ExportOnRequest1.removeAll();
    let matched = ds_ExportOnRequest.getMatchedJSON("gridChkBox", "1", true);
    if (!matched.length) {
      await $c.gus.cfAlertMsg($p, "승인취소내역을 선택하여 주십시오.");
      return;
    }
    if (matched.length == ds_ExportOnRequest.getRowCount()) {
      await $c.gus.cfAlertMsg($p, "전체승인취소 버튼을 이용하여 주십시오.");
      ds_ExportOnRequest.undoAll();
      ds_ExportOnRequest1.removeAll();
      return;
    }
    matched = matched.map(item => {
      return {
        "selfTransClntNo": item.selfTransClntNo,
        "onReqNo": item.onReqNo,
        "odrNo": item.odrNo,
        "cntrSeq": item.cntrSeq,
        "odrWrkPathSeq": item.odrWrkPathSeq,
        "odrWrkStpSeq": item.odrWrkStpSeq,
        "nrm": item.nrm
      };
    });
    ds_ExportOnRequest1.setJSON(matched);

    //pcy
    if (ed_vsslNm.getValue() != "") {
      ed_vsslCd.setValue(retrieve.vsslCd);
      ed_vsslNm.setValue(retrieve.vsslNm);
    }
    if (acb_admitClsCd2.getValue() == 'Y') {
      ds_retrieve.setCellData(0, "prebilgYn", 1);
    } else {
      ds_retrieve.setCellData(0, "prebilgYn", 0);
    }
    if ($c.gus.cfIsNull($p, retrieve.odrNo)) {
      if (retrieve.lineCd == "SKR" && $c.gus.cfIsNull($p, acb_admitClsCd2.getValue())) {
        await $c.win.alert($p, "SKR라인 수출상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
        return false;
      }
    }
    if (await $c.win.confirm($p, MSG_CM_CRM_011)) {
      $c.sbm.execute($p, sbm_cancel2);
    }
  }
};

/**
 * method
 * @name f_RowCopy
 * @description 행 복사
 */
scwin.f_RowCopy = function (row, colid, value) {
  let rowObj = ds_ExportOnRequest.getRowJSON(row);
  if (value === undefined) {
    value = rowObj[colid];
  }
  for (let idx = 0; idx < ds_ExportOnRequest.getRowCount(); idx++) {
    ds_ExportOnRequest.setCellData(idx, colid, value);
    switch (colid) {
      case "onWrkPlNm":
        ds_ExportOnRequest.setCellData(idx, "onWrkPlCd", rowObj.onWrkPlCd);
        break;
      case "onWrkPlCd":
        ds_ExportOnRequest.setCellData(idx, "onWrkPlNm", rowObj.onWrkPlNm);
        break;
      case "rtrnWrkPlNm":
        ds_ExportOnRequest.setCellData(idx, "rtrnWrkPlCd", rowObj.rtrnWrkPlCd);
        break;
      case "rtrnWrkPlCd":
        ds_ExportOnRequest.setCellData(idx, "rtrnWrkPlNm", rowObj.rtrnWrkPlNm);
        break;
    }
  }
};

