/**
 * event
 * @name btn_srchBookingNo_onclick
 * @description
 */
scwin.btn_srchBookingNo_onclick = async function (e) {
  // scwin.f_openCommonPopUp(3, '', '', 'T', 'T');
  const retrieve = ds_retrieve.getRowJSON(0);
  if (retrieve.bookingNo == "") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_INF_002);
    return;
  }
  if (retrieve.odrNo != "") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_INF_003);
    return;
  }
  let data = {
    param: `${retrieve.lineCd};${retrieve.bookingNo};${retrieve.selfTransClntNo};${retrieve.onReqNo};${retrieve.orgBookingNo}`
  };
  let opts = {
    id: "op_301_02_05p_popup",
    popupName: "Booking 정보 조회",
    modal: true,
    type: "browserPopup",
    //화면 오픈 타입 ("pageFramePopup", "browserPopup")
    title: "Win pop",
    //Layer pop
    width: 600,
    height: 450
  };
  await $c.win.openPopup($p, "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_05p.xml", opts, data);
  await scwin.f_Retrieve();
};

